with pexels_images as (
    select row_number() over () as rn, photo_id
    from unnest(array[
        356056,205421,577585,1181244,1181671,546819,574071,267350,669615,
        276724,1571460,1571463,1643383,1866149,1080721,271816,271795,276528,1457842,276554,271624,
        442576,3165335,7915357,3945652,4009626,2529148,1598505,298863,934070,1036623,845434,1152077,
        248528,404280,416528,209230,841130,863988,1435904,1124465,3769747,5082579,699122,682933,
        4219654,4397840,276517,1957477,301930,135620,279906,1599791,2101187,1667088,1139556,
        4482896,1148955,170811,210019,3802510,2127733,
        2047905,3184465,3861969,3861958,3861972,4145190,5380642,4050315,5054213,11035380,
        1571453,276583,276551,276566,2062426,2082090,2089698,3952034,3935333,6434630,7031406,
        214487,887751,349609,376464,1267320,1640777,70497,3026808,699953,2284166,
        2983464,934063,1036627,1036622,1124468,358070,1402787,
        36650873,16008946,17213759,14151893,28255122,16689203,13779109,8166627,9496427,11770971,
        32620372,13573921,17312557,9227842,
        1037992,1040424,1488463,1591060,1556707,994523,914668,428340,3756042,6311392,
        189349,326055,1279107,1027130,247204,461428,1111318,1229861,1181298,1181354,1181467,
        3184291,4974914,4491461,4792729,5698851,5082580,5082567,4210860,376401,276514,221185,
        280250,106399,279719,259588,2983101,3315286,3315291,3315294,2695232,7679720,7679722,
        7679726,3373736,572056,3985062,3985056,3985060,2115257,1120275,1334597,1092671,47261
    ]) as photo_id
),
ordered_products as (
    select
        id,
        row_number() over (order by created_at desc, id) as rn
    from product
    where status = 'ACTIVE'
),
picked as (
    select
        op.id,
        pi.photo_id,
        'https://images.pexels.com/photos/' || pi.photo_id || '/pexels-photo-' || pi.photo_id || '.jpeg?auto=compress&cs=tinysrgb&w=900' as image_url
    from ordered_products op
    join pexels_images pi on pi.rn = op.rn
)
update product p
   set image_url = picked.image_url,
       image_urls = json_build_array(
           picked.image_url,
           replace(picked.image_url, 'w=900', 'w=1200'),
           replace(picked.image_url, 'w=900', 'w=700')
       )::text
  from picked
 where p.id = picked.id;
